output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT DISTINCT ?teammate ?label WHERE {
  wd:Q49704 p:P54 ?sergioMem .
  ?sergioMem ps:P54 ?team .
  FILTER NOT EXISTS {
    ?sergioMem pq:P582 ?end
  }
  ?teammate p:P54 ?teammateMem .
  ?teammateMem ps:P54 ?team .
  FILTER NOT EXISTS {
    ?teammateMem pq:P582 ?end
  }
  FILTER(?teammate != wd:Q49704)
  ?teammate wdt:P31 wd:Q5 .
  OPTIONAL {
    ?teammate rdfs:label ?label .
    FILTER(lang(?label) = 'en')
  }
}
LIMIT 20

